const rawCall = $('Get Call').first().json;
const call = Array.isArray(rawCall) ? (rawCall[0] || {}) : (rawCall || {});
const callId = $('Webhook').first().json.body.call_id;
const transcript = (call.transcript_raw || '').trim();
const hasTranscript = transcript.length >= 50;
return [{ json: { call_id: callId, has_transcript: hasTranscript } }];

const responseText = ($input.first().json.text || $input.first().json.content?.[0]?.text || '').trim();
const callId = $('Webhook').first().json.body.call_id;
const rawRubricPS = $('Get Active Rubric').first().json;
const rubric = Array.isArray(rawRubricPS) ? (rawRubricPS[0] || null) : (rawRubricPS || null);

let cleanText = responseText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

// Fallback: if model returned markdown prose, extract the embedded JSON object
if (!cleanText.startsWith('{')) {
  const start = cleanText.indexOf('{');
  const end = cleanText.lastIndexOf('}');
  if (start !== -1 && end > start) cleanText = cleanText.substring(start, end + 1);
}

let sc;
try {
  sc = JSON.parse(cleanText);
} catch (e) {
  throw new Error('Failed to parse LLM scorecard: ' + responseText.substring(0, 300));
}

if (typeof sc.overall_score !== 'number') sc.overall_score = 0;
if (!Array.isArray(sc.strengths)) sc.strengths = [];
if (!Array.isArray(sc.improvements)) sc.improvements = [];
if (!sc.summary) sc.summary = '';

const allEvidence = [];

for (const s of sc.strengths) {
  if (s.evidence_quote) allEvidence.push({ criterion_key: s.criterion, quote: s.evidence_quote, timestamp_seconds: s.timestamp_seconds || null });
}
for (const s of sc.improvements) {
  if (s.evidence_quote) allEvidence.push({ criterion_key: s.criterion, quote: s.evidence_quote, timestamp_seconds: s.timestamp_seconds || null });
}

if (sc.meeting_phase) allEvidence.push({ criterion_key: 'meeting_phase', quote: String(sc.meeting_phase).trim(), timestamp_seconds: null });

for (const a of (sc.attendees || [])) allEvidence.push({ criterion_key: 'attendee', quote: String(a), timestamp_seconds: null });

if (sc.talk_time_breakdown && sc.talk_time_breakdown.length > 0) {
  allEvidence.push({ criterion_key: 'talk_time_breakdown', quote: JSON.stringify(sc.talk_time_breakdown), timestamp_seconds: null });
}

const LISTS = [
  ['key_points','key_point'],['decisions','decision'],['action_items','action_item'],
  ['next_steps','next_step'],['open_questions','open_question'],['risks','risk'],
  ['suggestions','suggestion'],['projects','project'],['banned_phrases','banned_phrase']
];
for (const [field, key] of LISTS) {
  for (const item of (sc[field] || [])) allEvidence.push({ criterion_key: key, quote: String(item), timestamp_seconds: null });
}

for (const p of (sc.coaching_priorities || [])) {
  if (p.priority >= 1 && p.priority <= 3) allEvidence.push({ criterion_key: 'coaching_priority_' + p.priority, quote: JSON.stringify(p), timestamp_seconds: null });
}

if (sc.meeting_effectiveness) allEvidence.push({ criterion_key: 'meeting_effectiveness', quote: JSON.stringify(sc.meeting_effectiveness), timestamp_seconds: null });

// Store new agent fields as evidence
if (sc.manager_summary) allEvidence.push({ criterion_key: 'manager_summary', quote: String(sc.manager_summary), timestamp_seconds: null });
if (sc.positive_reinforcement) allEvidence.push({ criterion_key: 'positive_reinforcement', quote: String(sc.positive_reinforcement), timestamp_seconds: null });
if (sc.rep_trajectory) allEvidence.push({ criterion_key: 'rep_trajectory', quote: String(sc.rep_trajectory), timestamp_seconds: null });
if (sc.comparison_note) allEvidence.push({ criterion_key: 'comparison_note', quote: String(sc.comparison_note), timestamp_seconds: null });

return [{ json: {
  call_id: callId,
  rubric_id: rubric ? rubric.id : null,
  overall_score: Math.round(sc.overall_score * 10) / 10,
  summary: sc.summary,
  strengths: sc.strengths,
  improvements: sc.improvements,
  llm_model: 'claude-sonnet-4-6',
  all_evidence: allEvidence
} }];

const scorecardRow = ($('Insert Scorecard').first().json || [])[0];
const scorecardId = scorecardRow ? scorecardRow.id : null;
const allEvidence = $('Parse Scorecard').first().json.all_evidence || [];
if (!scorecardId || allEvidence.length === 0) return [{ json: { __skip_evidence: true } }];
const evidenceRows = allEvidence.map(e => ({ scorecard_id: scorecardId, criterion_key: e.criterion_key, quote: e.quote, timestamp_seconds: e.timestamp_seconds }));
return [{ json: { evidence: evidenceRows } }];

